___CSS_LOADER_EXPORT___.push([module.id, `.ds-input-text {
  display: flex;
  flex-direction: column;
  gap: 2px;
  width: 100%;
}

.ds-input-text__label {
  display: flex;
  align-items: center;
  gap: var(--foundation-spacing-4, 4px);
  font-family: var(--semantic-font-family);
  font-size: var(--semantic-font-text-style-size-l);
  font-weight: var(--semantic-font-text-style-font-weight-regular);
  line-height: var(--semantic-font-text-style-line-height-l);
  color: var(--semantic-color-static-text-main-primary);
  cursor: pointer;
}

.ds-input-text__optional {
  color: var(--semantic-color-static-text-main-tertiary);
  font-size: var(--semantic-font-text-style-size-m);
}

.ds-input-text__container {
  display: flex;
  align-items: center;
  height: var(--semantic-measurement-spacing-xl);
  padding: 0 var(--semantic-measurement-spacing-s);
  gap: var(--semantic-measurement-spacing-s);
  border-radius: var(--semantic-border-radius-s);
  border: 1px solid var(--semantic-color-static-text-main-tertiary);
  background: var(--semantic-color-static-background-main-primary);
  transition: border-color 0.15s ease, background 0.15s ease;
}

.ds-input-text__container:hover {
  border-color: var(--semantic-color-interactive-border-medium-alt-hover);
}

.ds-input-text__input {
  flex: 1;
  min-width: 0;
  border: none;
  outline: none;
  background: transparent;
  font-family: var(--semantic-font-family);
  font-size: var(--semantic-font-text-style-size-l);
  font-weight: var(--semantic-font-text-style-font-weight-regular);
  line-height: var(--semantic-font-text-style-line-height-l);
  color: var(--semantic-color-static-text-main-primary);
}
.ds-input-text__input::placeholder {
  color: var(--semantic-color-static-text-main-tertiary);
}

.ds-input-text__container:focus-within {
  border-color: var(--semantic-color-interactive-border-strong-active);
  outline: 2px solid var(--semantic-color-interactive-border-focus);
  outline-offset: 1px;
}

.ds-input-text--error .ds-input-text__container {
  border-color: var(--semantic-color-interactive-border-strong-negative-default);
}

.ds-input-text__error-msg {
  font-size: var(--semantic-font-text-style-size-m);
  line-height: var(--semantic-font-text-style-line-height-m);
  color: var(--semantic-color-interactive-text-strong-negative-default);
}

.ds-input-text--readonly .ds-input-text__container {
  background: var(--semantic-color-static-background-main-secondary);
  cursor: default;
  pointer-events: none;
}

.ds-input-text--readonly .ds-input-text__container:hover {
  border-color: var(--semantic-color-static-text-main-tertiary);
}

.ds-input-text--disabled {
  opacity: var(--semantic-measurement-opacity-disabled);
  pointer-events: none;
}`, ""]);
